from langgraph.graph import StateGraph, END

def process_node(state: WorkflowState) -> WorkflowState:
    """Process the input."""
    result = f"Processed: {state['input']}"
    return {
        "output": result,
        "messages": [f"Processed input: {state['input']}"]
    }

def validate_node(state: WorkflowState) -> WorkflowState:
    """Validate the output."""
    if "error" in state["output"].lower():
        return {"error": "Validation failed"}
    return {"messages": ["Validation passed"]}

def finalize_node(state: WorkflowState) -> WorkflowState:
    """Finalize the workflow."""
    return {"messages": ["Workflow complete"]}

from langgraph.graph import StateGraph from typing import TypedDict
class ParallelState(TypedDict): input: str result_a: str result_b: str result_c: str final: str
def task_a(state: ParallelState) -> ParallelState: return {"result_a": f"A processed: {state['input']}"}
def task_b(state: ParallelState) -> ParallelState: return {"result_b": f"B processed: {state['input']}"}
def task_c(state: ParallelState) -> ParallelState: return {"result_c": f"C processed: {state['input']}"}
def combine(state: ParallelState) -> ParallelState: combined = f"{state['result_a']}, {state['result_b']}, {state['result_c']}" return {"final": combined}
# Build graph with parallel nodes graph = StateGraph(ParallelState) graph.add_node("task_a", task_a) graph.add_node("task_b", task_b) graph.add_node("task_c", task_c) graph.add_node("combine", combine)
# All three tasks run in parallel graph.set_entry_point("task_a") graph.set_entry_point("task_b") graph.set_entry_point("task_c")
# Wait for all to complete before combining graph.add_edge("task_a", "combine") graph.add_edge("task_b", "combine") graph.add_edge("task_c", "combine") graph.add_edge("combine", END)
parallel_workflow = graph.compile()

from langgraph.graph import StateGraph, END

class SafeState(TypedDict):
    input: str
    output: str
    error: str | None

def safe_node(state: SafeState) -> SafeState:
    try:
        result = risky_operation(state["input"])
        return {"output": result}
    except Exception as e:
        return {"error": str(e)}

def error_handler(state: SafeState) -> SafeState:
    """Handle errors gracefully."""
    return {"output": f"Error occurred: {state['error']}"}

def route_on_error(state: SafeState) -> str:
    if state.get("error"):
        return "error_handler"
    return "next_node"

graph = StateGraph(SafeState)
graph.add_node("risky", safe_node)
graph.add_node("error_handler", error_handler)
graph.add_node("next_node", next_node)

graph.add_conditional_edges("risky", route_on_error)

from langchain_openai import ChatOpenAI
from functools import lru_cache

@lru_cache(maxsize=100)
def expensive_operation(input: str) -> str:
    # Cached result
    return process(input)

cheap_model = ChatOpenAI(model="gpt-4o-mini")
expensive_model = ChatOpenAI(model="gpt-4o")

def smart_route(state: WorkflowState) -> str:
    if is_simple_task(state["input"]):
        return "cheap_node"
    return "expensive_node"
